import { Injectable } from '@angular/core';
import {
    HttpBackend,
    HttpClient,
    HttpRequest,
    HttpHeaders,
    HttpResponse
} from '@angular/common/http';
import { catchError, filter, map, Observable, tap, throwError } from 'rxjs';
import { environment } from 'src/environments/environment';
import { ApiUrls } from '../api-urls';
import { TokenService } from './token.service';

interface RefreshResponse {
    StatusCode: number | null;
    Error: string | null;
    Message: string;
    Data: {
        AccessToken: string;
        RefreshToken?: string;
    };
    Status: boolean;
    Page: any | null;
    TotalCount: number | null;
    PageSize: number | null;
    AreaLevel: any | null;
    EntityLevel: any | null;
}

@Injectable({ providedIn: 'root' })
export class ThirdPartyRefreshService {
    private http: HttpClient;
    private endpoint = `${environment.masterBaseUrl.replace(/\/+$/, '')}/${ApiUrls.User.RefreshThirdPartyToken.replace(/^\/+/, '')}`;

    constructor(handler: HttpBackend, private tokenStore: TokenService) {
        this.http = new HttpClient(handler);
    }

    refresh(refreshToken: string, authToken?: string): Observable<{ accessToken: string; refreshToken?: string }> {
        const bearer = authToken ?? this.tokenStore.ssoAccessToken ?? this.tokenStore.token ?? null;

        let req = new HttpRequest<any>(
            'POST',
            this.endpoint,
            { RefreshToken: refreshToken },
            {
                headers: new HttpHeaders({ 'Content-Type': 'application/json' }),
                reportProgress: false,
                responseType: 'json'
            }
        );

        if (bearer) {
            req = this.addAuth(req, bearer, 'HubAuthorization');
        }

        return this.http.request<RefreshResponse>(req).pipe(
            filter(evt => evt instanceof HttpResponse),
            map(evt => (evt as HttpResponse<RefreshResponse>).body as RefreshResponse),
            tap({
                next: (res) => {
                    if (res?.Data?.AccessToken) {
                        this.tokenStore.ssoAccessTokenSet(res.Data.AccessToken);

                        if (res.Data.RefreshToken) {
                            this.tokenStore.ssoRefreshTokenSet(res.Data.RefreshToken);
                        }
                    }
                }
            }),
            map(res => {
                if (!res?.Status) {
                    throw new Error(`Refresh failed: ${res?.Message || res?.Error || 'Unknown error'}`);
                }

                if (!res?.Data?.AccessToken) {
                    throw new Error(`Invalid refresh response: ${res?.Message || 'No access token'}`);
                }

                return {
                    accessToken: res.Data.AccessToken,
                    refreshToken: res.Data.RefreshToken
                };
            }),
            catchError(err => {
                return throwError(() => err);
            })
        );
    }

    private addAuth(
        req: HttpRequest<any>,
        token: string,
        headerName: 'Authorization' | 'HubAuthorization'
    ): HttpRequest<any> {
        return req.clone({ setHeaders: { [headerName]: `Bearer ${token}` } });
    }
}
